const SHEET_URL="https://docs.google.com/spreadsheets/d/e/2PACX-1vTlzWpkJU1L2-NKUzn0Hoe08-zIZ4rSTN-5RRneQPhdfMF5zQNUBOA1vG5dv9g3uc-Ue3DsMld6l3vI/pub?gid=0&single=true&output=csv";let masterLines=[],hat=[];async function loadLines(){try{const e=await fetch(SHEET_URL);if(!e.ok)throw new Error(`HTTP error! status: ${e.status}`);const t=await e.text();masterLines=t.split("\n").map((e=>e.trim())).filter((e=>e.length>0)),hat=[...masterLines],displayRandomLine()}catch(e){console.error("Error fetching sheet data:",e),document.getElementById("line-display").innerText="Error loading lines."}}function displayRandomLine(){if(0===masterLines.length)return;0===hat.length&&(hat=[...masterLines],console.log("The hat has been refilled with all lines!"));const e=Math.floor(Math.random()*hat.length);let t=hat.splice(e,1)[0];t.startsWith('"')&&t.endsWith('"')&&(t=t.slice(1,-1).replace(/""/g,'"')),document.getElementById("line-display").innerText=t}document.addEventListener("DOMContentLoaded",(()=>{const e=document.getElementById("next-btn");e&&e.addEventListener("click",displayRandomLine),loadLines()}));